const rows = $input.all();

function pickArray(root) {
  if (Array.isArray(root?.data?.comments)) return root.data.comments;
  if (Array.isArray(root?.data?.sub_comments)) return root.data.sub_comments;
  if (Array.isArray(root?.data?.replies)) return root.data.replies;
  if (Array.isArray(root?.data)) return root.data;
  return [];
}

function pickHasMore(root) {
  return root?.data?.has_more ?? false;
}

function pickCursor(root) {
  return root?.data?.cursor ?? '';
}

return rows.flatMap(item => {
  const root = item.json || {};
  const replies = pickArray(root);
  const hasMore = pickHasMore(root);
  const nextCursor = pickCursor(root);
  const cfg = $('Set API and Reply Parameters').first().json;

  return replies.map((reply, index) => {
    const user = reply.user || {};
    const replyUser = reply.reply_comment?.user || {};
    const atUsers = Array.isArray(reply.at_users) ? reply.at_users : [];
    const subComments = Array.isArray(reply.sub_comments) ? reply.sub_comments : [];

    return {
      json: {
        requestedNoteId: cfg.noteId || '',
        requestedCommentId: cfg.commentId || '',
        requestedLastCursor: cfg.lastCursor || '',
        replyIndex: index + 1,
        replyId: reply.id || '',
        noteId: reply.note_id || cfg.noteId || '',
        rootCommentId: reply.root_comment_id || cfg.commentId || '',
        parentCommentId: reply.parent_comment_id || '',
        content: reply.content || '',
        likeCount: reply.like_count ?? 0,
        subCommentCount: reply.sub_comment_count ?? 0,
        replyTime: reply.time ?? 0,
        ipLocation: reply.ip_location || '',
        liked: reply.liked ?? false,
        collected: reply.collected ?? false,
        status: reply.status ?? '',
        showType: reply.show_type || '',
        commentType: reply.comment_type ?? '',
        userId: user.userid || '',
        userNickname: user.nickname || '',
        userRedId: user.red_id || '',
        userAvatar: user.images || '',
        replyToUserId: replyUser.userid || '',
        replyToUserNickname: replyUser.nickname || '',
        atUsers,
        subComments,
        hasMore,
        nextCursor,
        raw: reply
      }
    };
  });
});
